select u.*, d.dept_name as department_name, r.role_code as primary_role_code from sys_user u left join sys_department d on d.id = u.department_id left join sys_user_role ur on ur.user_id = u.id left join sys_role r on r.id = ur.role_id and r.deleted = 0 and r.status = 'ENABLED' where u.deleted = 0
and u.status = #{status}
and (u.username like concat('%', #{keyword}, '%') or u.real_name like concat('%', #{keyword}, '%'))
order by u.id asc limit #{offset}, #{pageSize}


select u.*, d.dept_name as department_name, r.role_code as primary_role_code
from sys_user u
left join sys_department d on d.id = u.department_id
left join sys_user_role ur on ur.user_id = u.id
left join sys_role r on r.id = ur.role_id and r.deleted = 0 and r.status = 'ENABLED'
where u.deleted = 0 and u.department_id = #{departmentId}

  and u.status = #{status}


  and (u.username like concat('%', #{keyword}, '%') or u.real_name like concat('%', #{keyword}, '%'))

order by u.id asc
limit #{offset}, #{pageSize}

