update sys_user
set real_name=#{realName}, user_type=#{userType}, user_no=#{userNo}, gender=#{gender}, phone=#{phone}, email=#{email}, avatar_url=#{avatarUrl}, auth_type=#{authType}, department_id=#{departmentId}, unit_name=#{unitName}, title_name=#{titleName}, status=#{status}, remark=#{remark}, update_time=#{updateTime}
where id=#{id}

update sys_user
set status = #{status},
    remark = #{remark},
    update_time = #{updateTime}
where id = #{id}
  and deleted = 0
